SELECT industry_name
FROM naics_codes
WHERE naics_code = 1;

SELECT lender_name
FROM lenders
WHERE lender_type = 'bank';

SELECT COUNT(version_id) AS version_count
FROM loan_versions
WHERE loan_id = 1;

SELECT lender_name, created_at
FROM lenders
ORDER BY created_at DESC;

SELECT lender_name
FROM lenders
WHERE lender_id = 1;

SELECT COUNT(lender_id) AS total_banks
FROM lenders
WHERE lender_type = 'bank';

SELECT industry_name
FROM naics_codes
ORDER BY industry_name ASC;
